{"type":"freeform","cover":{"titleText":"","subTitleText":"","presenterText":"","dateText":"","logos":[]},"section":{"sectionText":"","smallerSectionText":""},"freeform":{"content":[[{"type":"text","span":3,"markdown":"ANC1 volumes trended upward from late 2024, peaking around March–May 2025 near 29,000 visits, and then stabilizing just below 28,000.

ANC4 showed slower but steady growth, reaching about 20,000 visits by mid-2025 — consistently ~8–9k lower than ANC1, indicating incomplete progression through visits.

Addressing gaps between first and fourth visits remains critical to ensure continuity of care and improved antenatal outcomes.","stretch":true,"fillArea":true,"textSize":1,"textBackground":"grey","placeholderInvisible":false,"placeholderStretch":true,"placeholderHeight":50,"useFigureAdditionalScale":false,"figureAdditionalScale":1,"imgHeight":300,"imgFit":"inside","imgStretch":true,"hideFigureCaption":false,"hideFigureSubCaption":false,"hideFigureFootnote":false},{"type":"figure","presentationObjectInReportInfo":{"id":"25641e45-d92c-48e9-b681-9d00af2681b4","moduleId":"m003","isDefault":false,"selectedReplicantValue":""},"stretch":true,"fillArea":false,"textSize":1,"textBackground":"none","placeholderInvisible":false,"placeholderStretch":true,"placeholderHeight":50,"useFigureAdditionalScale":true,"figureAdditionalScale":1,"imgHeight":300,"imgFit":"inside","imgStretch":true,"hideFigureCaption":false,"hideFigureSubCaption":false,"hideFigureFootnote":false}]],"useHeader":true,"headerText":"Trends in antenatal care","useFooter":false,"footerText":""}}

